import pandas as pd
from datetime import datetime

# Assuming var_functions.query_db:8 contains the query results
# Let's load the actual data from the stored JSON files

# The query_db calls return results stored as JSON strings
# We need to parse them
def parse_query_result(result_str):
    if isinstance(result_str, str):
        try:
            # If it's a file path, read it
            if '.json' in result_str and '/' in result_str:
                with open(result_str, 'r') as f:
                    return json.load(f)
            # Otherwise it's a JSON string
            return json.loads(result_str)
        except:
            return []
    return result_str

# Access the variables (they should be available in locals())
cases = locals().get('var_functions.query_db:8', [])
casehistory = locals().get('var_functions.query_db:14', [])

# Debug print
debug_info = {
    "cases_type": str(type(cases)),
    "casehistory_type": str(type(casehistory)),
    "cases_exists": cases is not None,
    "casehistory_exists": casehistory is not None
}

print("__RESULT__:")
print(json.dumps(debug_info))"}

